package entity_test

import (
	"testing"

	"github.com/nikita-rulenko/heisenbug-portal/internal/entity"
)

func TestUnitBenchA25A927E(t *testing.T) {
	tests := []struct {
		name  string
		items []entity.OrderItem
		want  float64
	}{
		{
			name:  "empty items",
			items: nil,
			want:  0,
		},
		{
			name: "zero quantity",
			items: []entity.OrderItem{
				{Quantity: 0, Price: 10.0},
			},
			want: 0,
		},
		{
			name: "negative price",
			items: []entity.OrderItem{
				{Quantity: 2, Price: -5.0},
			},
			want: -10.0,
		},
		{
			name: "large quantity",
			items: []entity.OrderItem{
				{Quantity: 1_000_000, Price: 1.23},
			},
			want: 1_000_000 * 1.23,
		},
		{
			name: "mixed positive and zero",
			items: []entity.OrderItem{
				{Quantity: 2, Price: 5.0},
				{Quantity: 0, Price: 100.0},
				{Quantity: 3, Price: 0.0},
			},
			want: 2*5.0 + 3*0.0,
		},
	}

	const epsilon = 1e-9

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			order := entity.Order{
				Items: tt.items,
			}
			order.CalculateTotal()
			if diff := order.Total - tt.want; diff > epsilon || diff < -epsilon {
				t.Fatalf("expected total %v, got %v", tt.want, order.Total)
			}
		})
	}
}

