package entity_test

// CHOICE: Product.ApplyDiscount — edge cases for discount clamping not covered
import (
	"math"
	"testing"

	"github.com/nikita-rulenko/heisenbug-portal/internal/entity"
)

func TestUnitBench52BB7795(t *testing.T) {
	const eps = 1e-9

	tests := []struct {
		name          string
		initialPrice  float64
		discount      float64
		expectedPrice float64
	}{
		{
			name:          "no discount leaves price unchanged",
			initialPrice:  100.0,
			discount:      0.0,
			expectedPrice: 100.0,
		},
		{
			name:          "normal percent discount",
			initialPrice:  200.0,
			discount:      25.0,
			expectedPrice: 150.0,
		},
		{
			name:          "negative discount is treated as zero",
			initialPrice:  80.0,
			discount:      -10.0,
			expectedPrice: 80.0,
		},
		{
			name:          "discount greater than 100% is clamped to 100%",
			initialPrice:  50.0,
			discount:      150.0,
			expectedPrice: 0.0,
		},
		{
			name:          "discount exactly 100% results in zero price",
			initialPrice:  123.45,
			discount:      100.0,
			expectedPrice: 0.0,
		},
	}

	for _, tc := range tests {
		tc := tc // capture range variable
		t.Run(tc.name, func(t *testing.T) {
			t.Parallel()
			p := &entity.Product{
				Price: tc.initialPrice,
			}
			p.ApplyDiscount(tc.discount)

			if math.Abs(p.Price-tc.expectedPrice) > eps {
				t.Errorf("ApplyDiscount(%v) on price %v: expected %v, got %v",
					tc.discount, tc.initialPrice, tc.expectedPrice, p.Price)
			}
		})
	}
}
